mapper.select:
SELECT id
FROM patient_doctor_favorite
WHERE patient_card_id = #{patientCardId}
  AND doctor_id = #{doctorId}
LIMIT 1

mapper.delete:
DELETE FROM patient_doctor_favorite
WHERE patient_card_id = #{patientCardId}
  AND doctor_id = #{doctorId}

mapper.select:
SELECT COUNT(*)
FROM patient_doctor_favorite
WHERE patient_card_id = #{patientCardId}
